class Solution {
public:
    long long maximumTripletValue(vector<int>& nums) {
        int n = nums.size();
        long long maxVal = 0;
        for (int j = 1; j < n - 1; ++j) {
            int maxLeft = nums[j - 1];
            int maxRight = nums[j + 1];
            int minLeft = nums[j - 1];
            for (int i = 0; i < j; ++i) {
                maxLeft = max(maxLeft, nums[i]);
                minLeft = min(minLeft, nums[i]);
            }
            for (int k = j + 2; k < n; ++k) {
                maxRight = max(maxRight, nums[k]);
            }
            maxVal = max(maxVal, (long long)(maxLeft - nums[j]) * maxRight);
            maxVal = max(maxVal, (long long)(minLeft - nums[j]) * maxRight);
        }
        return maxVal > 0 ? maxVal : 0;
    }
};
```

